import{_ as d,o as e,c as o,aw as a}from"./chunks/framework.DLufY-ao.js";const u=JSON.parse('{"title":"Псевдоклассы","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/layout/css/pseudo-classes/info.md","filePath":"wiki/dev-commit/layout/css/pseudo-classes/info.md"}'),r={name:"wiki/dev-commit/layout/css/pseudo-classes/info.md"};function c(n,t,i,l,h,s){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="псевдоклассы" tabindex="-1">Псевдоклассы <a class="header-anchor" href="#псевдоклассы" aria-label="Permalink to &quot;Псевдоклассы&quot;">​</a></h1><h2 id="варианты" tabindex="-1">Варианты <a class="header-anchor" href="#варианты" aria-label="Permalink to &quot;Варианты&quot;">​</a></h2><h3 id="пустые-элементы-и-отрицание-empty-not" tabindex="-1">Пустые элементы и отрицание: <code>:empty</code>, <code>:not</code> <a class="header-anchor" href="#пустые-элементы-и-отрицание-empty-not" aria-label="Permalink to &quot;Пустые элементы и отрицание: `:empty`, `:not`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдокласс</th><th>Описание</th></tr></thead><tbody><tr><td><code>p:empty</code></td><td>все пустые элементы p</td></tr><tr><td><code>p:not(:empty)</code></td><td>все не пустые элементы p</td></tr><tr><td><code>p:not(.myclass)</code></td><td>если p не имеет класса myclass</td></tr></tbody></table><h3 id="нумерация-и-дочерние-элементы-nth-of-type-only-child-nth-last-child-nth-last-of-type" tabindex="-1">Нумерация и дочерние элементы: <code>:nth-of-type</code>, <code>:only-child</code>, <code>:nth-last-child</code>, <code>:nth-last-of-type</code> <a class="header-anchor" href="#нумерация-и-дочерние-элементы-nth-of-type-only-child-nth-last-child-nth-last-of-type" aria-label="Permalink to &quot;Нумерация и дочерние элементы: `:nth-of-type`, `:only-child`, `:nth-last-child`, `:nth-last-of-type`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдокласс</th><th>Описание</th></tr></thead><tbody><tr><td><code>div:nth-of-type(2n)</code></td><td>каждый второй элемент определённого типа</td></tr><tr><td><code>div:only-child</code></td><td>только дочерние div</td></tr><tr><td><code>:nth-last-child</code></td><td>стиль по нумерации в дереве (отсчёт от последнего элемента, в отличие от :nth-child)</td></tr><tr><td><code>:nth-last-of-type</code></td><td>стиль к элементам указанного типа по нумерации (отсчёт от последнего, в отличие от :nth-of-type)</td></tr></tbody></table><h3 id="состояния-полеи-формы-checked-enabled-disabled-invalid-valid-optional-required-out-of-range-in-range-read-only-read-write" tabindex="-1">Состояния полей формы: <code>:checked</code>, <code>:enabled</code>, <code>:disabled</code>, <code>:invalid</code>, <code>:valid</code>, <code>:optional</code>, <code>:required</code>, <code>:out-of-range</code>, <code>:in-range</code>, <code>:read-only</code>, <code>:read-write</code> <a class="header-anchor" href="#состояния-полеи-формы-checked-enabled-disabled-invalid-valid-optional-required-out-of-range-in-range-read-only-read-write" aria-label="Permalink to &quot;Состояния полей формы: `:checked`, `:enabled`, `:disabled`, `:invalid`, `:valid`, `:optional`, `:required`, `:out-of-range`, `:in-range`, `:read-only`, `:read-write`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдокласс</th><th>Описание</th></tr></thead><tbody><tr><td><code>input:checked</code></td><td>выбранный элемент для checkbox и radio</td></tr><tr><td><code>input:enabled</code></td><td>активные элементы</td></tr><tr><td><code>input:disabled</code></td><td>неактивные элементы</td></tr><tr><td><code>input:invalid</code></td><td>поля, содержимое которых не соответствует типу (напр. незаполненные input с required)</td></tr><tr><td><code>input:valid</code></td><td>поля, содержимое которых соответствует указанному типу</td></tr><tr><td><code>input:optional</code></td><td>input без required</td></tr><tr><td><code>input:required</code></td><td>input с required</td></tr><tr><td><code>input:out-of-range</code></td><td>превышение лимита max в input number</td></tr><tr><td><code>input:in-range</code></td><td>в пределах min–max в input number</td></tr><tr><td><code>input:read-only</code></td><td>input с атрибутом readonly</td></tr><tr><td><code>input:read-write</code></td><td>input, доступные для изменения</td></tr></tbody></table><h3 id="ссылки-тип-элемента-и-язык-target-first-of-type-last-of-type-only-of-type-lang" tabindex="-1">Ссылки, тип элемента и язык: <code>:target</code>, <code>:first-of-type</code>, <code>:last-of-type</code>, <code>:only-of-type</code>, <code>:lang</code> <a class="header-anchor" href="#ссылки-тип-элемента-и-язык-target-first-of-type-last-of-type-only-of-type-lang" aria-label="Permalink to &quot;Ссылки, тип элемента и язык: `:target`, `:first-of-type`, `:last-of-type`, `:only-of-type`, `:lang`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдокласс</th><th>Описание</th></tr></thead><tbody><tr><td><code>div:target</code></td><td>стилизация элемента с id при переходе по ссылке (напр. <code>&lt;a href=&quot;#target1&quot;&gt;</code> → элемент <code>#target1</code>)</td></tr><tr><td><code>div:first-of-type</code></td><td>первый элемент определённого типа</td></tr><tr><td><code>div:last-of-type</code></td><td>последний элемент определённого типа</td></tr><tr><td><code>div:only-of-type</code></td><td>дочерний элемент указанного типа, если он единственный у родителя</td></tr><tr><td><code>div:lang</code></td><td>язык, используемый в документе</td></tr></tbody></table><h3 id="специальные-состояния-root-default-fullscreen-indeterminate" tabindex="-1">Специальные состояния: <code>:root</code>, <code>:default</code>, <code>:fullscreen</code>, <code>:indeterminate</code> <a class="header-anchor" href="#специальные-состояния-root-default-fullscreen-indeterminate" aria-label="Permalink to &quot;Специальные состояния: `:root`, `:default`, `:fullscreen`, `:indeterminate`&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдокласс</th><th>Описание</th></tr></thead><tbody><tr><td><code>:root</code></td><td>корневой элемент документа</td></tr><tr><td><code>:default</code></td><td>элемент по умолчанию (напр. одна из двух кнопок submit)</td></tr><tr><td><code>:fullscreen</code></td><td>полноэкранный режим</td></tr><tr><td><code>:indeterminate</code></td><td>переключатель в неопределённом состоянии</td></tr></tbody></table>',12)])])}const f=d(r,[["render",c]]);export{u as __pageData,f as default};
